import{_ as t,a as n,b as a,c as i}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as r,o as d,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const z=JSON.parse('{"title":"WebDAV-Kanal hinzufügen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/webdav.md","filePath":"de-DE/upload/webdav.md","lastUpdated":1781962217000}'),h={name:"de-DE/upload/webdav.md"};function o(u,e,c,p,g,b){return d(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="webdav-kanal-hinzufugen" tabindex="-1">WebDAV-Kanal hinzufügen <a class="header-anchor" href="#webdav-kanal-hinzufugen" aria-label="Permalink to &quot;WebDAV-Kanal hinzufügen&quot;">​</a></h1><h2 id="geeignet-fur" tabindex="-1">Geeignet für <a class="header-anchor" href="#geeignet-fur" aria-label="Permalink to &quot;Geeignet für&quot;">​</a></h2><p>Nutze den WebDAV-Kanal, wenn:</p><ul><li>du ein NAS, einen Cloudspeicher oder einen Objektspeicherdienst mit WebDAV-Endpunkt hast.</li><li>hochgeladene Bilder in deinem eigenen WebDAV-Verzeichnis gespeichert werden sollen.</li><li>Zugangsdaten in der D1-Tabelle <code>upload_channels</code> gespeichert werden sollen, statt dauerhaft im Frontend sichtbar zu sein.</li></ul><h2 id="was-du-vorher-brauchst" tabindex="-1">Was du vorher brauchst <a class="header-anchor" href="#was-du-vorher-brauchst" aria-label="Permalink to &quot;Was du vorher brauchst&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Zweck</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Serverseitige WebDAV-URL, z. B. <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Benutzername</td><td>Für die Anmeldung am WebDAV-Dienst.</td></tr><tr><td>Passwort</td><td>Für die Anmeldung am WebDAV-Dienst.</td></tr><tr><td>Authentifizierungsmodus</td><td>Standard ist <code>Basic</code>. Nutze <code>Digest</code> oder automatische Aushandlung nur, wenn der Server es verlangt.</td></tr><tr><td>Speicherverzeichnis</td><td>Ordner, in dem Dateien gespeichert werden. Standard ist <code>imgbed</code>.</td></tr></tbody></table><h2 id="wo-hinzufugen" tabindex="-1">Wo hinzufügen <a class="header-anchor" href="#wo-hinzufugen" aria-label="Permalink to &quot;Wo hinzufügen&quot;">​</a></h2><ol><li>Öffne die Systemeinstellungen.</li><li>Gehe zu Upload-Einstellungen.</li><li>Klicke oben rechts auf Kanal hinzufügen.</li><li>Wähle <code>WebDAV</code>.</li></ol><h2 id="feldubersicht" tabindex="-1">Feldübersicht <a class="header-anchor" href="#feldubersicht" aria-label="Permalink to &quot;Feldübersicht&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feld</th><th>Funktion</th><th>Erforderlich</th></tr></thead><tbody><tr><td>Kanalname</td><td>Ein gut erkennbarer Name für diesen WebDAV-Kanal, z. B. <code>koofr</code> oder <code>nas</code>.</td><td>Ja</td></tr><tr><td>Endpoint</td><td>Vollständiger WebDAV-Endpunkt inklusive <code>https://</code>.</td><td>Ja</td></tr><tr><td>Benutzername</td><td>WebDAV-Anmeldename.</td><td>Ja</td></tr><tr><td>Passwort</td><td>WebDAV-Passwort.</td><td>Ja</td></tr><tr><td>Authentifizierungsmodus</td><td>Meist <code>Basic</code>; nutze <code>Digest</code>, wenn der Server Digest-Authentifizierung verlangt.</td><td>Ja</td></tr><tr><td>Speicherverzeichnis</td><td>Ordner, in dem Dateien abgelegt werden. Standard ist <code>imgbed</code>.</td><td>Nein</td></tr></tbody></table><h2 id="beispiel-fie-nl-tab-digital" tabindex="-1">Beispiel: fie.nl.tab.digital <a class="header-anchor" href="#beispiel-fie-nl-tab-digital" aria-label="Permalink to &quot;Beispiel: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-app-passwort-erstellen" tabindex="-1">1. App-Passwort erstellen <a class="header-anchor" href="#_1-app-passwort-erstellen" aria-label="Permalink to &quot;1. App-Passwort erstellen&quot;">​</a></h3><p>Öffne die Sicherheitseinstellungen deines Kontos, suche die App-Passwörter und erstelle ein neues App-Passwort.</p><p><img src="'+t+'" alt="App-Passwort erstellen" loading="lazy"></p><p>Kopiere und speichere das neue App-Passwort direkt nach dem Erstellen. In der Regel wird es nur einmal angezeigt.</p><p><img src="'+n+'" alt="Neues App-Passwort speichern" loading="lazy"></p><h3 id="_2-webdav-konfiguration-in-imgbed-ausfullen" tabindex="-1">2. WebDAV-Konfiguration in ImgBed ausfüllen <a class="header-anchor" href="#_2-webdav-konfiguration-in-imgbed-ausfullen" aria-label="Permalink to &quot;2. WebDAV-Konfiguration in ImgBed ausfüllen&quot;">​</a></h3><p>Kehre zu ImgBed zurück und füge einen WebDAV-Kanal hinzu:</p><table tabindex="0"><thead><tr><th>UI-Feld</th><th>Wert</th></tr></thead><tbody><tr><td>Endpoint</td><td>Die von <code>https://fie.nl.tab.digital/</code> bereitgestellte WebDAV-URL.</td></tr><tr><td>Benutzername</td><td>Dein WebDAV-Benutzername.</td></tr><tr><td>Passwort</td><td>Das gerade erstellte App-Passwort.</td></tr><tr><td>Authentifizierungsmodus</td><td>Starte in den meisten Fällen mit <code>Basic</code>.</td></tr><tr><td>Speicherverzeichnis</td><td>Standard ist <code>imgbed</code>; du kannst auch einen eigenen Ordner verwenden.</td></tr></tbody></table><p><img src="'+a+'" alt="Konfiguration ausfüllen" loading="lazy"></p><h2 id="verhalten-bei-großen-dateien" tabindex="-1">Verhalten bei großen Dateien <a class="header-anchor" href="#verhalten-bei-großen-dateien" aria-label="Permalink to &quot;Verhalten bei großen Dateien&quot;">​</a></h2><p>Der WebDAV-Kanal verwendet inzwischen echtes sitzungsbasiertes Chunk-Upload.</p><p>Kleine Dateien werden als vollständige Einzeldatei hochgeladen. Dateien größer als 64 MiB werden automatisch in etwa 10 MiB große Teile aufgeteilt und in ein Remote-Chunk-Verzeichnis hochgeladen.</p><p>Der WebDAV-Dienst muss keine <code>partial update</code>- oder Offset-basierten Schreibvorgänge unterstützen. ImgBed setzt die Chunks auf dem Remote-Server nicht wieder zu einer großen Datei zusammen. Stattdessen speichert ImgBed ein Chunk-Manifest und liest die Teile bei einem Dateiaufruf der Reihe nach aus.</p><p>Praktisch bedeutet das:</p><table tabindex="0"><thead><tr><th>Dateigröße</th><th>Upload-Methode</th><th>Remote-Speicherlayout</th></tr></thead><tbody><tr><td>64 MiB oder kleiner</td><td>Normaler Upload</td><td>Eine vollständige Datei</td></tr><tr><td>Größer als 64 MiB</td><td>Echtes sitzungsbasiertes Chunk-Upload</td><td>Ein Chunk-Verzeichnis mit mehreren Teil-Dateien</td></tr></tbody></table><p>Das Chunk-Verzeichnis betrifft nur die Ablage im entfernten Speicher. Die Datei-URL in ImgBed ändert sich dadurch nicht. Nutzer öffnen die Datei weiterhin über den ursprünglichen <code>/file/...</code>-Link.</p><h2 id="einrichtungsschritte" tabindex="-1">Einrichtungsschritte <a class="header-anchor" href="#einrichtungsschritte" aria-label="Permalink to &quot;Einrichtungsschritte&quot;">​</a></h2><ol><li>Öffne die Upload-Einstellungen.</li><li>Klicke auf Kanal hinzufügen.</li><li>Wähle <code>WebDAV</code>.</li><li>Trage einen gut erkennbaren Kanalnamen ein, z. B. <code>koofr</code>.</li><li>Trage den WebDAV-Endpunkt ein, z. B. <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Trage Benutzername und Passwort ein.</li><li>Lasse den Authentifizierungsmodus standardmäßig auf <code>Basic</code>.</li><li>Lasse das Speicherverzeichnis bei <code>imgbed</code> oder ändere es auf deinen eigenen Ordner.</li><li>Klicke auf Speichern.</li><li>Prüfe nach dem Speichern die Kanalkarte, frage bei Bedarf die Kapazität ab und lade eine Testdatei hoch.</li></ol><h2 id="prufung" tabindex="-1">Prüfung <a class="header-anchor" href="#prufung" aria-label="Permalink to &quot;Prüfung&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prüfung</th><th>So prüfst du es</th></tr></thead><tbody><tr><td>Kanalkarte erscheint</td><td>Nach dem Speichern sollte in den Upload-Einstellungen eine WebDAV-Kanalkarte sichtbar sein.</td></tr><tr><td>Kanal ist aktiv</td><td>Der Schalter oben rechts auf der Karte bleibt eingeschaltet.</td></tr><tr><td>Zugangsdaten sind gespeichert</td><td>Die Detailansicht zeigt Endpoint, Benutzername, Authentifizierungsmodus und Speicherverzeichnis.</td></tr><tr><td>Kleine Datei lädt hoch</td><td>Lade ein Testbild hoch und prüfe, ob es im WebDAV-Verzeichnis erscheint.</td></tr><tr><td>Regel für große Dateien greift</td><td>Dateien über 64 MiB nutzen Chunk-Upload und erzeugen ein Remote-Chunk-Verzeichnis.</td></tr><tr><td>Kapazitätsabfrage funktioniert</td><td>Wenn der Server Kapazitätsinformationen unterstützt, werden belegter und gesamter Speicher angezeigt.</td></tr></tbody></table><p><img src="'+i+`" alt="Quotenabfrage erfolgreich" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="warum-erzeugen-große-webdav-dateien-ein-chunk-verzeichnis" tabindex="-1">Warum erzeugen große WebDAV-Dateien ein Chunk-Verzeichnis? <a class="header-anchor" href="#warum-erzeugen-große-webdav-dateien-ein-chunk-verzeichnis" aria-label="Permalink to &quot;Warum erzeugen große WebDAV-Dateien ein Chunk-Verzeichnis?&quot;">​</a></h3><p>Das ist die aktuelle Speichermethode für große Dateien.</p><p>Dateien über 64 MiB werden nicht zu einer einzelnen großen Remote-Datei zusammengefügt. Sie werden als Chunk-Verzeichnis gespeichert. ImgBed merkt sich das Chunk-Manifest und gibt den vollständigen Inhalt zurück, indem die Teile der Reihe nach gelesen werden.</p><h3 id="was-sollte-ich-zuerst-prufen-wenn-große-uploads-fehlschlagen" tabindex="-1">Was sollte ich zuerst prüfen, wenn große Uploads fehlschlagen? <a class="header-anchor" href="#was-sollte-ich-zuerst-prufen-wenn-große-uploads-fehlschlagen" aria-label="Permalink to &quot;Was sollte ich zuerst prüfen, wenn große Uploads fehlschlagen?&quot;">​</a></h3><p>Prüfe zuerst Endpoint, Benutzername, Passwort und Speicherverzeichnis. Stelle danach sicher, dass der WebDAV-Dienst Ordner anlegen, Dateien schreiben und Dateien lesen darf.</p><p>Wenn die Kapazitätsabfrage fehlschlägt, kleine Uploads aber funktionieren, unterstützt der Server die Kapazitätsauskunft möglicherweise nicht oder schränkt sie ein. Das bedeutet nicht automatisch, dass Uploads unmöglich sind.</p><h3 id="welchen-authentifizierungsmodus-soll-ich-wahlen" tabindex="-1">Welchen Authentifizierungsmodus soll ich wählen? <a class="header-anchor" href="#welchen-authentifizierungsmodus-soll-ich-wahlen" aria-label="Permalink to &quot;Welchen Authentifizierungsmodus soll ich wählen?&quot;">​</a></h3><p>Starte mit <code>Basic</code>.</p><p>Wenn der Server ausdrücklich Digest-Authentifizierung verlangt, nutze <code>Digest</code>.</p><p>Wenn du unsicher bist, nutze automatische Aushandlung.</p><h2 id="kurzcheck" tabindex="-1">Kurzcheck <a class="header-anchor" href="#kurzcheck" aria-label="Permalink to &quot;Kurzcheck&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebDAV-Endpunkt, Benutzername und Passwort vorbereiten</span></span>
<span class="line"><span>-&gt; Upload-Einstellungen öffnen</span></span>
<span class="line"><span>-&gt; Kanal hinzufügen</span></span>
<span class="line"><span>-&gt; WebDAV wählen</span></span>
<span class="line"><span>-&gt; Endpoint / Benutzername / Passwort eintragen</span></span>
<span class="line"><span>-&gt; Authentifizierungsmodus standardmäßig auf Basic lassen</span></span>
<span class="line"><span>-&gt; Speicherverzeichnis standardmäßig auf imgbed lassen</span></span>
<span class="line"><span>-&gt; Speichern</span></span>
<span class="line"><span>-&gt; Kapazität abfragen</span></span>
<span class="line"><span>-&gt; Testdatei hochladen</span></span></code></pre></div>`,45)])])}const k=r(h,[["render",o]]);export{z as __pageData,k as default};
